<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer 
                                v-if="parameter.length > 0" 
                                :key="loadKey"
                                :viewerId="'viewer_' + loadKey"
                                :parameter="parameter" 
                                :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            loadKey: 0,  // NEW: Track unique load for keys/IDs
            DataLoaded: 0,
            DateFormat: "M/D/YYYY",  // NEW: Initialize DateFormat
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Client Name"),
                            name: "Clientname",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Client'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.GetUtilityByClient
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Utility Name"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Modified By"),
                            name: "ModifiedBy",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "DateField",
                            label: this.$t('Resolved Date From(M/D/YYYY)'),
                            name: "ResolvedFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {                                
                                 format: "M/D/YYYY",
                                 onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Resolved Date To(M/D/YYYY)'),
                            name: "ResolvedToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {
                                 format: "M/D/YYYY",
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Flag Date From(M/D/YYYY)'),
                            name: "FlagFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {
                                 format: "M/D/YYYY",
                                 onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Flag Date To(M/D/YYYY)'),
                            name: "FlagToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {
                                 format: "M/D/YYYY"
                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "textField",
                            label: this.$t("Ticket Number"),
                            name: "TicketNumber",
                            value: "",
                            placeholder: "Ticket Number"
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Work Date From(M/D/YYYY)'),
                            name: "WorkDateFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {
                                 format: "M/D/YYYY",
                                 onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Work Date To(M/D/YYYY)'),
                            name: "WorkDateToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {
                                 format: "M/D/YYYY"
                            }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("Cost Centers"),
                            name: "CostCenters",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DateFormat = vm.GetUserInfo.DateFormat || "M/D/YYYY";  // FIXED: Use || for fallback
        vm.DataLoaded = 1;
        await vm.GetCostCenters();
        await vm.GetClient();
        await vm.GetUsers();       
    },
    methods: {
        setTimerDate:function(x, y, z){
            var vm =this;
            if(y.name == "ResolvedFromdate"){                           
                vm.$refs.BarcodeReport.updateProperty("ResolvedToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            } 
            if(y.name == "FlagFromdate"){                           
                vm.$refs.BarcodeReport.updateProperty("FlagToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            }  
            if(y.name == "WorkDateFromdate"){                           
                vm.$refs.BarcodeReport.updateProperty("WorkDateToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            }  
        }, 
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options=[];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[2].value = '';
            (vm.FormSchema)[2].Data[3].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;  // NEW: Reset loadKey on clear
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom=null&search=null&userId=null';
            await DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUtilityByClient: async function (x, y, z) {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options=[];
            vm.FormSchema[0].Data[1].value = ''; 
            var ClientIds = z.value;  // FIXED: Use z.value for selected item
            var url = `clientId=${ClientIds}&configid=0&Reqfrom=&clientIds=`;
            await DataServices.GetUtilityByClient(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.UTILITY_NAME,
                            value: element.UTILITY_ID
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUsers: async function () {
            var vm = this;
            var params = `isType=false&moduleName=InvoiceReport`;
            await DataServices.GetUsers(params).then((response) => {
                if (response.data != '') {
                    var UsersData = response.data;
                    UsersData.forEach(item => {
                        vm.FormSchema[0].Data[2].config.options.push({
                            name: item.UserName,
                            value: item.UserId
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    CostCentresData.forEach(item => {
                        vm.FormSchema[2].Data[3].config.options.push({
                            name: item.text,
                            value: item.value
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        async onSubmit(e) {
            // REMOVED: Manual destroy - unique key will handle component recreation
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();  // NEW: Generate unique key for this load
            vm.reportPath = '';
            vm.parameter = [];
            
            let myObj = {
                reportName: "flagdetailreport",
                ClientIds: e.Clientname ? e.Clientname.toString() : '',

                UtilityIds: Array.isArray(e.UtilityName) && e.UtilityName.length > 0
                    ? e.UtilityName.map(item => item.value).join(",") : '',

                userIds: Array.isArray(e.ModifiedBy) && e.ModifiedBy.length > 0
                    ? e.ModifiedBy.map(item => item.value).join(",")  : '',

                
                resolvedFromDate: e.ResolvedFromdate ? new Date(e.ResolvedFromdate).toISOString(): null,

                resolvedToDate: e.ResolvedToDate ? new Date(e.ResolvedToDate).toISOString() : null,

                createdFromDate: e.FlagFromdate ? new Date(e.FlagFromdate).toISOString() : null,

                createdToDate: e.FlagToDate? new Date(e.FlagToDate).toISOString(): null,

                TicketNumber: e.TicketNumber || '',

                WorkDateFrom: e.WorkDateFromdate? new Date(e.WorkDateFromdate).toISOString(): null,

                WorkDateTo: e.WorkDateToDate? new Date(e.WorkDateToDate).toISOString() : null,
             
                CostCenterId: e.CostCenters || ''
            };

            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        }
    }
};
</script>